4	
5	const BASE_URL: &str = "/api";
6	
7	pub struct ApiClient {
8	    token: Option<String>,
9	}
10	
11	impl ApiClient {
12	    pub fn new() -> Self {
13	        Self { token: None }
14	    }
15	
16	    pub fn with_token(token: String) -> Self {
17	        Self { token: Some(token) }
18	    }
19	
20	    fn build_url(path: &str) -> String {
21	        format!("{}{}", BASE_URL, path)
22	    }
23	
24	    // ---- Static methods (used by most pages) ----
25	
26	    pub async fn get<T: DeserializeOwned>(path: &str, token: Option<&str>) -> Result<T, String> {
27	        let url = Self::build_url(path);
28	        let mut req = Request::get(&url);
29	        if let Some(t) = token {
30	            req = req.header("Authorization", &format!("Bearer {}", t));
31	        }
32	        let resp = req.send().await.map_err(|e| e.to_string())?;
33	        if !resp.ok() {
34	            let status = resp.status();
35	            let body = resp.text().await.unwrap_or_default();
36	            return Err(format!("HTTP {}: {}", status, body));
37	        }
38	        resp.json::<T>().await.map_err(|e| e.to_string())
39	    }
40	
41	    pub async fn post<T: DeserializeOwned, B: Serialize>(
42	        path: &str,
43	        body: &B,
44	        token: Option<&str>,
45	    ) -> Result<T, String> {
46	        let url = Self::build_url(path);
47	        let mut req = Request::post(&url)
48	            .header("Content-Type", "application/json");
49	        if let Some(t) = token {
50	            req = req.header("Authorization", &format!("Bearer {}", t));
51	        }
52	        let json_body = serde_json::to_string(body).map_err(|e| e.to_string())?;
53	        let resp = req.body(&json_body)
54	            .map_err(|e| e.to_string())?
55	            .send()
56	            .await
57	            .map_err(|e| e.to_string())?;
58	        if !resp.ok() {
59	            let status = resp.status();
60	            let body = resp.text().await.unwrap_or_default();
61	            return Err(format!("HTTP {}: {}", status, body));
62	        }
63	        resp.json::<T>().await.map_err(|e| e.to_string())
64	    }
65	
66	    pub async fn post_no_response<B: Serialize>(
67	        path: &str,
68	        body: &B,
69	        token: Option<&str>,
70	    ) -> Result<(), String> {
71	        let url = Self::build_url(path);
72	        let mut req = Request::post(&url)
73	            .header("Content-Type", "application/json");
74	        if let Some(t) = token {
75	            req = req.header("Authorization", &format!("Bearer {}", t));
