82	            .map_err(|e| e.to_string())?;
83	        if !resp.ok() {
84	            let status = resp.status();
85	            let body = resp.text().await.unwrap_or_default();
86	            return Err(format!("HTTP {}: {}", status, body));
87	        }
88	        Ok(())
89	    }
