116	    pub async fn delete(path: &str, token: Option<&str>) -> Result<(), String> {
117	        let url = Self::build_url(path);
118	        let mut req = Request::delete(&url);
119	        if let Some(t) = token {
120	            req = req.header("Authorization", &format!("Bearer {}", t));
121	        }
122	        let resp = req.send().await.map_err(|e| e.to_string())?;
