1	/// Scoring page: evaluation workflow with template picker, question-level grading,
2	/// partial credit input, progress indicator, and second-review status cues.
3	/// QA Reviewers can process pending second reviews inline.
4	
5	use dioxus::prelude::*;
6	
7	use crate::state::AuthState;
8	
9	#[derive(Debug, Clone, PartialEq)]
10	enum ScoringTab {
11	    Evaluations,
12	    NewEvaluation,
13	    PendingReviews,
14	}
15	
16	#[component]
17	pub fn Scoring() -> Element {
18	    let auth = use_context::<Signal<AuthState>>();
19	    let mut active_tab = use_signal(|| ScoringTab::Evaluations);
20	
21	    let can_read = auth.read().has_permission("api.scoring.read");
22	    let can_write = auth.read().has_permission("api.scoring.write");
23	
24	    if !can_read {
25	        return rsx! {
26	            div { class: "page-header",
27	                h1 { "Quality Scoring" }
28	                p { style: "color: var(--color-text-secondary);",
29	                    "You do not have permission to view scoring data."
30	                }
31	            }
32	        };
33	    }
34	
35	    rsx! {
36	        div {
37	            div { class: "page-header",
38	                h1 { "Quality Scoring" }
39	                p { "Evaluate service delivery quality, review auto-scored and manual responses, and manage second-review escalations." }
40	            }
41	
42	            // Tab navigation
43	            div { style: "display: flex; gap: 4px; border-bottom: 2px solid var(--color-border); margin-bottom: 24px;",
44	                TabButton {
45	                    label: "Evaluations",
46	                    active: *active_tab.read() == ScoringTab::Evaluations,
47	                    onclick: move |_| { *active_tab.write() = ScoringTab::Evaluations; }
48	                }
49	                if can_write {
50	                    TabButton {
51	                        label: "New Evaluation",
52	                        active: *active_tab.read() == ScoringTab::NewEvaluation,
53	                        onclick: move |_| { *active_tab.write() = ScoringTab::NewEvaluation; }
54	                    }
55	                }
56	                TabButton {
57	                    label: "Pending Reviews",
58	                    active: *active_tab.read() == ScoringTab::PendingReviews,
59	                    onclick: move |_| { *active_tab.write() = ScoringTab::PendingReviews; }
60	                }
61	            }
62	
63	            match *active_tab.read() {
64	                ScoringTab::Evaluations => rsx! { EvaluationsTab {} },
65	                ScoringTab::NewEvaluation => rsx! { NewEvaluationTab {} },
66	                ScoringTab::PendingReviews => rsx! { PendingReviewsTab { can_write: can_write } },
67	            }
68	        }
69	    }
70	}
