1	/// Degradation toggles: centrally controlled feature flags that disable
2	/// expensive or risky operations when the system is under stress.
3	///
4	/// Supported toggles (stored in `ops_config`):
5	///   - `exports_enabled`   (bool) — when false, all export requests return 503
6	///   - `analytics_enabled` (bool) — when false, heavy report queries return 503
7	///
8	/// Each toggle change is:
9	///   1. Written to the `ops_config` table (persistent across restarts)
10	///   2. Logged to `ops_events` for the compliance trail
11	///   3. Logged to the structured event log via tracing
12	///   4. Written to the `audit_logs` table via AuditService
13	///
14	/// The in-memory cache is a simple Arc<RwLock<HashMap>> with no TTL.
15	/// Cache is populated lazily on first read and invalidated on every write.
16	/// This is appropriate for local-network deployments where the DB is fast.
17	
18	use std::collections::HashMap;
19	use std::sync::{Arc, RwLock};
20	
21	use sqlx::MySqlPool;
22	use uuid::Uuid;
23	
24	use crate::domain::error::AppError;
25	use crate::infrastructure::audit::{AuditEntry, AuditService};
26	
27	/// Known toggle keys — adding a new toggle requires adding it here and seeding it.
28	pub const TOGGLE_EXPORTS: &str = "exports_enabled";
29	pub const TOGGLE_ANALYTICS: &str = "analytics_enabled";
30	
31	pub const KNOWN_TOGGLES: &[&str] = &[TOGGLE_EXPORTS, TOGGLE_ANALYTICS];
32	
33	/// In-memory flag cache to avoid a DB round-trip on every request.
34	type FlagCache = Arc<RwLock<HashMap<String, bool>>>;
35	
36	#[derive(Clone)]
37	pub struct DegradationService {
38	    pool: MySqlPool,
39	    audit: AuditService,
40	    cache: FlagCache,
41	}
42	
43	#[derive(Debug, serde::Serialize, serde::Deserialize)]
44	pub struct OpsFlag {
45	    pub key_name: String,
46	    pub value: bool,
47	    pub updated_by: String,
48	    pub updated_at: String,
49	}
50	
51	impl DegradationService {
52	    pub fn new(pool: MySqlPool, audit: AuditService) -> Self {
53	        Self {
54	            pool,
55	            audit,
56	            cache: Arc::new(RwLock::new(HashMap::new())),
57	        }
58	    }
59	
60	    /// Seed default flag values into ops_config if they don't already exist.
61	    /// Called from seed_service.rs after user seeding completes.
62	    pub async fn seed_defaults(&self, system_user_id: &str) -> Result<(), AppError> {
63	        for key in KNOWN_TOGGLES {
64	            let existing: Option<(String,)> = sqlx::query_as(
65	                "SELECT value FROM ops_config WHERE key_name = ?"
66	            )
67	            .bind(key)
68	            .fetch_optional(&self.pool)
69	            .await
70	            .map_err(|e| AppError::Internal(e.to_string()))?;
71	
72	            if existing.is_none() {
73	                sqlx::query(
74	                    "INSERT INTO ops_config (key_name, value, updated_by) VALUES (?, 'true', ?)"
75	                )
76	                .bind(key)
77	                .bind(system_user_id)
78	                .execute(&self.pool)
79	                .await
80	                .map_err(|e| AppError::Internal(e.to_string()))?;
81	            }
82	        }
83	        Ok(())
84	    }
85	
86	    /// Get a toggle value. Returns `true` if the key is missing (fail-open by default).
87	    pub async fn get_flag(&self, key: &str) -> bool {
88	        // Try cache first
89	        {
90	            let cache = self.cache.read().expect("degradation cache read lock poisoned");
91	            if let Some(v) = cache.get(key) {
92	                return *v;
93	            }
94	        }
95	
96	        // Cache miss: load from DB
97	        let row: Option<(String,)> = sqlx::query_as(
98	            "SELECT value FROM ops_config WHERE key_name = ?"
99	        )
100	        .bind(key)
101	        .fetch_optional(&self.pool)
102	        .await
103	        .unwrap_or(None);
104	
105	        let value = row
106	            .and_then(|(v,)| v.parse::<bool>().ok())
107	            .unwrap_or(true); // fail-open
108	
109	        {
110	            let mut cache = self.cache.write().expect("degradation cache write lock poisoned");
111	            cache.insert(key.to_string(), value);
112	        }
113	
114	        value
115	    }
116	
117	    /// Set a toggle value.
118	    /// Returns Err if the key is unknown or if the DB write fails.
119	    pub async fn set_flag(
120	        &self,
121	        key: &str,
122	        new_value: bool,
123	        actor_id: &str,
124	    ) -> Result<(), AppError> {
125	        if !KNOWN_TOGGLES.contains(&key) {
126	            return Err(AppError::BadRequest(format!(
127	                "Unknown ops flag '{}'. Known flags: {}",
128	                key,
129	                KNOWN_TOGGLES.join(", ")
130	            )));
131	        }
132	
133	        // Read old value for audit trail
134	        let old_value = self.get_flag(key).await;
135	
136	        // Update DB
