19	#[rocket::async_trait]
20	impl<'r> FromRequest<'r> for AuthenticatedUser {
21	    type Error = Json<ErrorEnvelope>;
22	
23	    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Self::Error> {
24	        let auth_header = match request.headers().get_one("Authorization") {
25	            Some(h) => h,
26	            None => {
27	                return Outcome::Error((
28	                    Status::Unauthorized,
29	                    Json(AppError::Unauthorized("Missing Authorization header".to_string()).envelope()),
30	                ));
31	            }
32	        };
33	
34	        let token = if auth_header.starts_with("Bearer ") {
35	            &auth_header[7..]
36	        } else {
37	            return Outcome::Error((
38	                Status::Unauthorized,
39	                Json(AppError::Unauthorized("Invalid Authorization header format".to_string()).envelope()),
40	            ));
41	        };
42	
43	        let auth_service = match request.rocket().state::<AuthService>() {
44	            Some(svc) => svc,
45	            None => {
46	                return Outcome::Error((
47	                    Status::InternalServerError,
48	                    Json(AppError::Internal("Auth service unavailable".to_string()).envelope()),
49	                ));
50	            }
51	        };
52	
53	        match auth_service.validate_token(token).await {
54	            Ok(claims) => Outcome::Success(AuthenticatedUser {
55	                user_id: claims.sub.clone(),
56	                session_id: claims.session_id.clone(),
57	                org_id: claims.org_id.clone(),
58	                claims,
59	            }),
60	            Err(e) => Outcome::Error((
61	                Status::Unauthorized,
62	                Json(e.envelope()),
63	            )),
64	        }
65	    }
66	}
