21	        let is_local = app_env == "local";
22	
23	        let database_url = std::env::var("DATABASE_URL").unwrap_or_else(|_| {
24	            if is_local {
25	                "mysql://careops_user:careops_pass@db:3306/careops".to_string()
26	            } else {
27	                panic!("DATABASE_URL must be set in non-local environments (APP_ENV={})", app_env);
28	            }
29	        });
30	
31	        let jwt_secret = std::env::var("JWT_SECRET").unwrap_or_else(|_| {
32	            if is_local {
33	                tracing::warn!("JWT_SECRET not set — using insecure development default. Do NOT use in production.");
34	                "careops-dev-jwt-secret-change-in-production-min-32-chars!".to_string()
