43	                "careops-dev-encryption-key-0123456789abcdef".to_string()
44	            } else {
45	                panic!("ENCRYPTION_KEY must be set in non-local environments (APP_ENV={})", app_env);
46	            }
47	        });
48	
49	        Self {
50	            database_url,
51	            app_env,
