                if err_str.contains("Duplicate entry") || err_str.contains("uq_payments_org_idempotency_key") {
                    return Err(AppError::Conflict(format!(
                        "Duplicate request: a payment with idempotency_key '{}' was already recorded for this organization",
                        req.idempotency_key
                    )));
                }
                return Err(AppError::Internal(err_str));
            }
        }

        // Insert fund_transaction (immutable ledger)
        sqlx::query(
            "INSERT INTO fund_transactions
             (id, org_id, invoice_id, transaction_type, amount, direction, reference_id, actor_id)
             VALUES (?, ?, ?, 'payment', ?, 'credit', ?, ?)"
        )
        .bind(&fund_tx_id)
        .bind(org_id)
        .bind(&req.invoice_id)
        .bind(amount_rounded)
        .bind(&payment_id)  // reference_id points to the payment record
        .bind(user_id)
        .execute(&self.pool)
        .await
        .map_err(|e| AppError::Internal(e.to_string()))?;"}

