    } else {
        "padding: 8px 16px; border: none; border-bottom: 2px solid transparent; background: transparent; cursor: pointer; color: var(--color-text-secondary);"
    };
    rsx! {
        button { style: style, onclick: move |e| onclick.call(e), "{label}" }
    }
}
