151	
152	            return Err(AppError::Unauthorized("Invalid credentials".to_string()));
153	        }
154	
155	        // Reset failed attempts on success
156	        sqlx::query("UPDATE user_credentials SET failed_attempts = 0, locked_until = NULL WHERE user_id = ?")
157	            .bind(&user_id)
158	            .execute(&self.pool)
159	            .await
160	            .ok();
161	
162	        // Create session
163	        let session_id = Uuid::new_v4().to_string();
164	        let now = Utc::now();
165	        let expires_at = now + Duration::hours(self.session_ttl_hours as i64);
166	
167	        let claims = JwtClaims {
168	            sub: user_id.clone(),
169	            session_id: session_id.clone(),
170	            org_id: org_id.clone(),
171	            exp: expires_at.timestamp() as usize,
172	            iat: now.timestamp() as usize,
173	        };
174	
175	        let token = encode(
176	            &Header::default(),
177	            &claims,
178	            &EncodingKey::from_secret(self.jwt_secret.as_bytes()),
179	        )
180	        .map_err(|e| AppError::Internal(format!("Token generation failed: {}", e)))?;
181	
182	        // Store session with hashed token
183	        let token_hash = hex::encode(Sha256::digest(token.as_bytes()));
184	        sqlx::query(
185	            "INSERT INTO sessions (id, user_id, token_hash, issued_at, expires_at, ip_address, user_agent)
186	             VALUES (?, ?, ?, ?, ?, ?, ?)"
187	        )
188	        .bind(&session_id)
189	        .bind(&user_id)
190	        .bind(&token_hash)
191	        .bind(now.naive_utc())
192	        .bind(expires_at.naive_utc())
193	        .bind(&ip_address)
194	        .bind(&user_agent)
195	        .execute(&self.pool)
196	        .await
197	        .map_err(|e| AppError::Internal(e.to_string()))?;
198	
199	        // Load permissions for the response
200	        let perms = self.perm_cache.get_permissions(&user_id).await
201	            .map_err(|e| AppError::Internal(e.to_string()))?;
202	
203	        let profile = UserProfile {
204	            id: user_id.clone(),
205	            org_id: org_id.clone(),
206	            department_id,
207	            username,
208	            email,
209	            status,
210	            roles: perms.role_names.into_iter().collect(),
211	            permissions: perms.permission_codes.into_iter().collect(),
212	        };
