228	    /// Validate a JWT token and return the claims.
229	    pub async fn validate_token(&self, token: &str) -> Result<JwtClaims, AppError> {
230	        let claims = decode::<JwtClaims>(
231	            token,
232	            &DecodingKey::from_secret(self.jwt_secret.as_bytes()),
233	            &Validation::default(),
234	        )
235	        .map_err(|e| AppError::Unauthorized(format!("Invalid token: {}", e)))?
236	        .claims;
237	
238	        // Verify session is not revoked
239	        let token_hash = hex::encode(Sha256::digest(token.as_bytes()));
240	        let session: Option<(Option<chrono::NaiveDateTime>,)> = sqlx::query_as(
241	            "SELECT revoked_at FROM sessions WHERE id = ? AND token_hash = ?"
242	        )
243	        .bind(&claims.session_id)
244	        .bind(&token_hash)
245	        .fetch_optional(&self.pool)
246	        .await
247	        .map_err(|e| AppError::Internal(e.to_string()))?;
248	
249	        match session {
250	            Some((Some(_revoked),)) => Err(AppError::Unauthorized("Session has been revoked".to_string())),
251	            Some((None,)) => Ok(claims),
252	            None => Err(AppError::Unauthorized("Session not found".to_string())),
253	        }
254	    }
