256	    /// Invalidate a session (logout).
257	    pub async fn logout(&self, session_id: &str, user_id: &str) -> Result<(), AppError> {
258	        sqlx::query("UPDATE sessions SET revoked_at = NOW() WHERE id = ? AND user_id = ?")
259	            .bind(session_id)
260	            .bind(user_id)
261	            .execute(&self.pool)
262	            .await
263	            .map_err(|e| AppError::Internal(e.to_string()))?;
264	
265	        self.audit.log(AuditEntry {
266	            user_id: Some(user_id.to_string()),
267	            action: actions::LOGOUT.to_string(),
268	            resource_type: "auth".to_string(),
269	            resource_id: Some(session_id.to_string()),
270	            org_id: None,
271	            details: None,
272	            ip_address: None,
273	            trace_id: None,
274	        }).await;
275	
276	        Ok(())
277	    }
