279	    /// Get the current user's profile with permissions.
280	    pub async fn get_current_user(&self, user_id: &str) -> Result<UserProfile, AppError> {
281	        let row: (String, String, Option<String>, String, String, String) = sqlx::query_as(
282	            "SELECT id, org_id, department_id, username, email, status FROM users WHERE id = ?"
283	        )
284	        .bind(user_id)
285	        .fetch_one(&self.pool)
286	        .await
287	        .map_err(|e| AppError::NotFound(format!("User not found: {}", e)))?;
288	
289	        let perms = self.perm_cache.get_permissions(user_id).await
290	            .map_err(|e| AppError::Internal(e.to_string()))?;
291	
292	        Ok(UserProfile {
293	            id: row.0,
294	            org_id: row.1,
